mapper.select:
SELECT DISTINCT res.* FROM sys_resource res JOIN sys_role_resource rr ON res.id = rr.resource_id WHERE rr.role_code IN
#{code}
AND res.status = #{status}
ORDER BY res.sort_order ASC

SELECT DISTINCT res.*
FROM sys_resource res
         JOIN sys_role_resource rr ON res.id = rr.resource_id
         JOIN sys_role role ON rr.role_code = role.role_code
         JOIN sys_user_role ur ON ur.role_code = role.role_code
WHERE ur.username = #{username}

    AND role.status = #{status}
    AND res.status = #{status}

ORDER BY res.sort_order ASC
